    final sessionValid = await _validateSession();
    if (!sessionValid) {
      result.requiresReauthentication = true;
    }

    final transactionSignature = _generateTransactionSignature(amount, currency);
    result.transactionSignature = transactionSignature;

    result.isValid = true;
    return result;
