  Future<bool> _validateSession() async {
    if (_sessionToken == null || _sessionExpiry == null) {
      return false;
    }
    
    if (DateTime.now().isAfter(_sessionExpiry!)) {
      await invalidateSession();
      return false;
    }

    return true;
