    try {
      final securityValidation = await _securityManager.validatePaymentSecurity(
        amount: 0,
        currency: 'USD',
        requireStrictIntegrity: false,
      );

      if (securityValidation.integrityResult?.isHighRisk ?? false) {
        await _securityManager.logSecurityEvent('product_fetch_blocked', {
          'reason': 'High risk device',
        });
        throw PaymentException('Cannot fetch products on compromised device');
      }

      final result = await _channel.invokeMethod('getProducts', {
        'productIds': productIds,
      });

      final products = (result as List).map((p) => Product.fromJson(Map<String, dynamic>.from(p))).toList();
      return products;
    } catch (e) {
      throw PaymentException('Failed to fetch products: $e');
    }
  }

  Future<PurchaseResult> purchaseProduct(String productId) async {
    try {
      final securityValidation = await _securityManager.validatePaymentSecurity(
        amount: 0,
        currency: 'USD',
        requireStrictIntegrity: true,
      );

      if (!securityValidation.isValid) {
        await _securityManager.logSecurityEvent('iap_blocked', {
          'productId': productId,
          'reason': securityValidation.failureReason,
        });

        return PurchaseResult(
          success: false,
          productId: productId,
          errorMessage: 'Purchase blocked due to security concerns',
        );
