      await _securityManager.logSecurityEvent('iap_initiated', {
        'productId': productId,
      });

      final result = await _channel.invokeMethod('purchaseProduct', {
        'productId': productId,
        'deviceIntegrity': securityValidation.integrityResult?.toJson(),
      });

      final purchaseResult = PurchaseResult.fromJson(Map<String, dynamic>.from(result));

      await _securityManager.logSecurityEvent('iap_completed', {
        'productId': productId,
        'success': purchaseResult.success,
      });

      return purchaseResult;
    } catch (e) {
      await _securityManager.logSecurityEvent('iap_error', {
        'productId': productId,
        'error': e.toString(),
      });
      throw PaymentException('Purchase failed: $e');
    }
  }

  Future<bool> verifyPurchase(String purchaseToken) async {
    try {
      final securityValidation = await _securityManager.validatePaymentSecurity(
        amount: 0,
        currency: 'USD',
        requireStrictIntegrity: true,
      );

      final result = await _channel.invokeMethod('verifyPurchase', {
        'purchaseToken': purchaseToken,
        'deviceIntegrity': securityValidation.integrityResult?.toJson(),
      });

      return result as bool;
    } catch (e) {
      throw PaymentException('Purchase verification failed: $e');
    }
  }

  Future<void> restorePurchases() async {
    try {
      final securityValidation = await _securityManager.validatePaymentSecurity(
        amount: 0,
        currency: 'USD',
        requireStrictIntegrity: false,
      );

      if (securityValidation.integrityResult?.isHighRisk ?? false) {
        throw PaymentException('Cannot restore purchases on compromised device');
      }

      await _channel.invokeMethod('restorePurchases');
    } catch (e) {
      throw PaymentException('Restore purchases failed: $e');
    }
