  String toString() => 'SecureStorageException: $message';
}

class PaymentModule {
  late final PaymentProcessor paymentProcessor;
  late final InAppPurchaseManager inAppPurchaseManager;
  late final MobileWalletManager mobileWalletManager;
  final PaymentSecurityManager _securityManager = PaymentSecurityManager();

  PaymentModule({required PaymentGatewayConfig config}) {
    paymentProcessor = PaymentProcessor(config: config);
    inAppPurchaseManager = InAppPurchaseManager();
    mobileWalletManager = MobileWalletManager();
  }

  Future<void> initialize(String userId) async {
    await _securityManager.createSession(userId);
    
    final integrityResult = await DeviceIntegrityService().checkDeviceIntegrity();
    
    await _securityManager.logSecurityEvent('payment_module_initialized', {
      'userId': userId,
      'deviceIntegrity': integrityResult.toJson(),
    });
  }

  Future<void> shutdown() async {
    await _securityManager.invalidateSession();
    DeviceIntegrityService().resetIntegrityCheck();
  }

  Future<DeviceIntegrityResult> checkDeviceIntegrity() async {
    return await DeviceIntegrityService().checkDeviceIntegrity();
  }
}